mapper.select:
/* DSBRD_PC_Dao_retrieveCbnNtrltList */ WITH MONTH_LIST AS ( SELECT /*+ MATERIALZE */ TO_CHAR(ADD_MONTHS(TO_DATE(SUBSTR(#{strtDt}, 0, 6), 'yyyyMM'), LEVEL - 1), 'yyyyMM') AS mt FROM DUAL CONNECT BY LEVEL <= MONTHS_BETWEEN(TO_DATE(SUBSTR(#{endDt}, 0, 6), 'yyyyMM'), TO_DATE(SUBSTR(#{strtDt}, 0, 6), 'yyyyMM')) + 1 ), DSQTY_DATA_INIT_LIST AS ( SELECT /*+ MATERIALZE LEADING(BBB EEE FFF AAA) */ BBB.dscfc_id, BBB.dscfc_bplc_cd, BBB.dscfc_procs_ty_cd, ( SELECT A.cmmn_cd_nm FROM ( SELECT cmmn_cd, cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'SC' AND cls_cd = 'GHG_0024' ) A, ( SELECT cmmn_cd, cmmn_cd_nm, usr_dfn_vu2 FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_1003' ) B WHERE A.cmmn_cd = B.usr_dfn_vu2 AND A.cmmn_cd_nm IS NOT NULL AND A.cmmn_cd = BBB.dscfc_procs_ty_cd ) AS dscfc_procs_ty_nm, BBB.dscfc_lclhq_cd, AAA.sum_dscfc_usgqty, AAA.dscfc_use_de, CASE WHEN BBB.dscfc_use_fuel_div_cd = '61' THEN (NVL(AAA.sum_dscfc_usgqty, '0') * AAA.co2_gesu / 1000 ) WHEN BBB.dscfc_use_fuel_div_cd <> '61' THEN (NVL(AAA.sum_dscfc_usgqty, '0') / 1000 * EEE.emsnsrc_clrval_cfcnt * AAA.co2_gesu * 1 / 1000000) END AS co2_dsqty, CASE WHEN BBB.dscfc_use_fuel_div_cd = '61' THEN ((NVL(AAA.sum_dscfc_usgqty, '0') * AAA.ch4_gesu * 1000 ) / 1000) WHEN BBB.dscfc_use_fuel_div_cd <> '61' THEN (NVL(AAA.sum_dscfc_usgqty, '0') / 1000 * EEE.emsnsrc_clrval_cfcnt * 1 * AAA.ch4_gesu / 1000) END AS ch4_dsqty, CASE WHEN BBB.dscfc_use_fuel_div_cd = '61' THEN ((NVL(AAA.sum_dscfc_usgqty, '0') * AAA.n2o_gesu * 1000 ) / 1000) WHEN BBB.dscfc_use_fuel_div_cd <> '61' THEN (NVL(AAA.sum_dscfc_usgqty, '0') / 1000 * EEE.emsnsrc_clrval_cfcnt * AAA.n2o_gesu * 1 / 1000) END AS n2o_dsqty FROM GHG.tm_gg01101 BBB, GHG.tm_gg01106 EEE, GHG.te_gg01101 FFF, ( SELECT ABC.dscfc_id, ABC.dscfc_use_de, MAX(ABC.usgqty) AS sum_dscfc_usgqty, MAX(ABC.co2_gesu) AS co2_gesu, MAX(ABC.ch4_gesu) AS ch4_gesu, MAX(ABC.n2o_gesu) AS n2o_gesu FROM ( SELECT AA.dscfc_id, AA.dscfc_use_de, CASE WHEN AA.dsqty_cfrml_parm_id IN ('2005', '2001') THEN MAX(AA.dscfc_usgqty) END AS usgqty, CASE WHEN AA.dsqty_cfrml_parm_nm LIKE '%CO2배출계수' THEN MAX(AA.dscfc_usgqty) END AS co2_gesu, CASE WHEN AA.dsqty_cfrml_parm_nm LIKE '%CH4배출계수' THEN MAX(AA.dscfc_usgqty) END AS ch4_gesu, CASE WHEN AA.dsqty_cfrml_parm_nm LIKE '%N2O배출계수' THEN MAX(AA.dscfc_usgqty) END AS n2o_gesu FROM ( SELECT /*+ LEADING(B A) */ A.dscfc_id, A.dscfc_use_de, B.dsqty_cfrml_parm_id, B.dsqty_cfrml_parm_nm, A.dscfc_usgqty FROM GHG.tm_rq01103 A, GHG.tm_gg01104 B WHERE ( B.dsqty_cfrml_parm_nm LIKE '%CH4배출계수' OR B.dsqty_cfrml_parm_nm LIKE '%CO2배출계수' OR B.dsqty_cfrml_parm_nm LIKE '%N2O배출계수' OR A.dsqty_cfrml_parm_id IN ('2005', '2001') ) AND ( (A.dscfc_use_slip_no IS NOT NULL AND A.dscfc_use_slip_no NOT LIKE 'TMP%') OR A.dscfc_use_slip_prcs_ty_cd = '1' ) AND ( dscfc_use_de BETWEEN ( SELECT MIN(mt) FROM MONTH_LIST ) || '01' AND ( SELECT MAX(mt) FROM MONTH_LIST ) || '31' ) AND A.dsqty_cfrml_parm_id = B.dsqty_cfrml_parm_id ) AA GROUP BY AA.dscfc_id, AA.dscfc_use_de, AA.dsqty_cfrml_parm_id, AA.dsqty_cfrml_parm_nm ) ABC GROUP BY ABC.dscfc_id, ABC.dscfc_use_de ) AAA WHERE BBB.dscfc_id = AAA.dscfc_id AND BBB.dscfc_use_fuel_div_cd = FFF.dscfc_use_fuel_div_cd AND EEE.emsnsrc_id = FFF.emsnsrc_id AND BBB.dscfc_use_yn = '1' AND BBB.dscfc_regist_stat_div_cd = '1'
AND BBB.dscfc_use_fuel_div_cd = '61' /* 전기 */ AND BBB.dscfc_lclhq_cd != '88888888' /* 위탁 */
), DSQTY_DATA_LIST AS ( SELECT /*+ MATERIALZE */ dscfc_use_de, ROUND(NVL(ieq, 0), 0) AS ieq, ROUND(NVL(prn, 0), 0) AS prn, ROUND(NVL(clwr, 0), 0) AS clwr, ROUND(NVL(ofcrk, 0), 0) AS ofcrk, ROUND(NVL(trnsprt, 0), 0) AS trnsprt, ROUND(NVL(dam, 0), 0) AS dam, ROUND(NVL(etc, 0), 0) AS etc, ( NVL(ieq, 0) + NVL(prn, 0) + NVL(clwr, 0) + NVL(ofcrk, 0) + NVL(trnsprt, 0) + NVL(dam, 0) + NVL(etc, 0) ) AS tot FROM ( SELECT AAA.dscfc_use_de, ROUND(SUM(DECODE(AAA.dscfc_procs_ty_cd, '01', AAA.ggss_dsqty, 0)), 1) AS ieq, ROUND(SUM(DECODE(AAA.dscfc_procs_ty_cd, '02', AAA.ggss_dsqty, 0)), 1) AS prn, ROUND(SUM(DECODE(AAA.dscfc_procs_ty_cd, '03', AAA.ggss_dsqty, 0)), 1) AS clwr, ROUND(SUM(DECODE(AAA.dscfc_procs_ty_cd, '04', AAA.ggss_dsqty, 0)), 1) AS ofcrk, ROUND(SUM(DECODE(AAA.dscfc_procs_ty_cd, '05', AAA.ggss_dsqty, 0)), 1) AS trnsprt, ROUND(SUM(DECODE(AAA.dscfc_procs_ty_cd, '06', AAA.ggss_dsqty, 0)), 1) AS dam, ROUND(SUM(DECODE(AAA.dscfc_procs_ty_cd, '99', AAA.ggss_dsqty, 0)), 1) AS etc FROM ( SELECT SUBSTR(AAAAA.dscfc_use_de, 0, 6) AS dscfc_use_de, AAAAA.dscfc_procs_ty_cd, NVL(ROUND((SUM(AAAAA.co2_dsqty) * 1 + (TRUNC(SUM(AAAAA.ch4_dsqty), 3) * 21 + TRUNC(SUM(AAAAA.n2o_dsqty), 3) * 310 ) / 1000 ), 3), 0) AS ggss_dsqty FROM DSQTY_DATA_INIT_LIST AAAAA WHERE IN ( SELECT objid FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsBasinDivCd}
) OR dscfc_lclhq_cd = '88888888' GROUP BY SUBSTR(AAAAA.dscfc_use_de, 0, 6), AAAAA.dscfc_procs_ty_cd ) AAA WHERE AAA.dscfc_use_de BETWEEN ( SELECT MIN(mt) FROM MONTH_LIST ) AND ( SELECT MAX(mt) FROM MONTH_LIST ) GROUP BY AAA.dscfc_use_de ) ), RQTY_DATA_INIT_LIST AS ( SELECT /*+ MATERIALZE */ AS hq_cd, AAA.elcpwstn_mnggrp_dept_cd AS dscfc_bplc_cd, AAA.elcpwstn_cls_cd, ( SELECT cmmn_cd_nm FROM (
) B WHERE B.elcpwstn_cls_cd LIKE '%' || AAA.elcpwstn_cls_cd || '%' AND cnd LIKE '%01%' AND ROWNUM = 1 ) AS elcpwstn_cls_nm, SUM(AAA.elyrs_qy) AS elyrs_qy, SUBSTR(AAA.stdr_de, 0, 6) AS stdr_de, AAA.g_co2, AAA.g_ch4, AAA.g_n2o, ROUND(ROUND((ROUND(NVL(SUM(AAA.elyrs_qy), '0'), 3 ) * AAA.g_co2 / 1000 ), 3) * 1 + ( TRUNC(((ROUND(NVL(SUM(AAA.elyrs_qy), '0'), 3 ) * AAA.g_ch4 * 1000 ) / 1000 ), 3) * 21 + TRUNC(((ROUND(NVL(SUM(AAA.elyrs_qy), '0'), 3 ) * AAA.g_n2o * 1000 ) / 1000 ), 3) * 310 ) / 1000, 3) AS ggss_rqty FROM ( SELECT AA.hq_cd, AA.elcpwstn_mnggrp_dept_cd, AA.elcpwstn_cls_cd, AA.elyrs_qy, AA.stdr_de, ( SELECT B.dsqty_cfrml_parm_vu FROM GHG.tm_gg01104 A, GHG.td_gg01102 B WHERE A.dsqty_cfrml_parm_id = B.dsqty_cfrml_parm_id AND AA.stdr_de BETWEEN dsqty_cfrml_parm_applc_de AND dsqty_cfrml_parm_end_de AND A.dsqty_cfrml_parm_id IN ('10675', '10676', '10677', '11433', '12662', '12663', '12664') AND A.dsqty_cfrml_parm_nm LIKE '%CO2배출계수' ) AS G_CO2, ( SELECT B.dsqty_cfrml_parm_vu FROM GHG.tm_gg01104 A, GHG.td_gg01102 B WHERE A.dsqty_cfrml_parm_id = B.dsqty_cfrml_parm_id AND AA.stdr_de BETWEEN dsqty_cfrml_parm_applc_de AND dsqty_cfrml_parm_end_de AND A.dsqty_cfrml_parm_id IN ('10675', '10676', '10677', '11433', '12662', '12663', '12664') AND A.dsqty_cfrml_parm_nm LIKE '%CH4배출계수' ) AS g_ch4, ( SELECT B.dsqty_cfrml_parm_vu FROM GHG.tm_gg01104 A, GHG.td_gg01102 B WHERE A.dsqty_cfrml_parm_id = B.dsqty_cfrml_parm_id AND AA.stdr_de BETWEEN dsqty_cfrml_parm_applc_de AND dsqty_cfrml_parm_end_de AND A.dsqty_cfrml_parm_id IN ('10675', '10676', '10677', '11433', '12662', '12663', '12664') AND A.dsqty_cfrml_parm_nm LIKE '%N2O배출계수' ) AS g_n2o FROM ( SELECT hq_cd, elcpwstn_mnggrp_dept_cd, elcpwstn_cls_cd, elyrs_qy, stdr_de FROM WRO.vm_eg04105_15 WHERE stdr_de BETWEEN ( SELECT MIN(mt) FROM MONTH_LIST ) || '01' AND ( SELECT MAX(mt) FROM MONTH_LIST ) || '31' ) AA ) AAA GROUP BY AAA.hq_cd, AAA.elcpwstn_mnggrp_dept_cd, AAA.elcpwstn_cls_cd, SUBSTR(AAA.stdr_de, 0, 6), AAA.g_co2, AAA.g_ch4, AAA.g_n2o ), RQTY_DATA_LIST AS ( SELECT /*+ MATERIALZE */ stdr_de, ROUND(NVL(lwp, 0), 0) AS lwp, ( ROUND(NVL(fmr, 0), 0) + ROUND(NVL(swp, 0), 0) ) AS swp, ROUND(NVL(tp, 0), 0) AS tp, ( ROUND(NVL(kwpv, 0), 0) + ROUND(NVL(kcpv, 0), 0) ) AS pv, ROUND(NVL(wp, 0), 0) AS wp, ( NVL(lwp, 0) + (NVL(fmr, 0) + NVL(swp, 0)) + NVL(tp, 0) + (NVL(kwpv, 0) + NVL(kcpv, 0)) + NVL(wp, 0) ) AS tot FROM ( SELECT AAAA.stdr_de, ROUND(SUM(DECODE(AAAA.elcpwstn_cls_cd, '0000', AAAA.ggss_rqty, 0)), 1) AS etc, ROUND(SUM(DECODE(AAAA.elcpwstn_cls_cd, '0001', AAAA.ggss_rqty, 0)), 1) AS lwp, ROUND(SUM(DECODE(AAAA.elcpwstn_cls_cd, '0002', AAAA.ggss_rqty, 0)), 1) AS swp, ROUND(SUM(DECODE(AAAA.elcpwstn_cls_cd, '0003', AAAA.ggss_rqty, 0)), 1) AS tp, ROUND(SUM(DECODE(AAAA.elcpwstn_cls_cd, '0004', AAAA.ggss_rqty, 0)), 1) AS kwpv, ROUND(SUM(DECODE(AAAA.elcpwstn_cls_cd, '0005', AAAA.ggss_rqty, 0)), 1) AS kcpv, ROUND(SUM(DECODE(AAAA.elcpwstn_cls_cd, '0006', AAAA.ggss_rqty, 0)), 1) AS wp, ROUND(SUM(DECODE(AAAA.elcpwstn_cls_cd, '0007', AAAA.ggss_rqty, 0)), 1) AS fmr FROM RQTY_DATA_INIT_LIST AAAA WHERE AAAA.dscfc_bplc_cd IS NOT NULL AND IN ( SELECT objid FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsBasinDivCd}
) AND AAAA.stdr_de BETWEEN ( SELECT MIN(mt) FROM MONTH_LIST ) AND ( SELECT MAX(mt) FROM MONTH_LIST ) GROUP BY AAAA.stdr_de ) ), DATA_LIST AS ( SELECT /*+ MATERIALZE LEADING(B C YEAR_LIST) */ YEAR_LIST.yy, ROUND(NVL(B.tot, 0), 1) AS dsqty_sum, ROUND(NVL(C.tot, 0), 1) AS rqty_sum, CASE WHEN C.tot > 0 AND B.tot > 0 THEN ROUND(C.tot / B.tot * 100, 1) ELSE 0 END AS acmtrt FROM ( SELECT SUBSTR(mt, 0, 4) AS yy FROM MONTH_LIST GROUP BY SUBSTR(mt, 0, 4) ) YEAR_LIST, ( SELECT SUBSTR(dscfc_use_de, 0, 4) AS yy, SUM(tot) AS tot FROM DSQTY_DATA_LIST GROUP BY SUBSTR(dscfc_use_de, 0, 4) ) B, ( SELECT SUBSTR(stdr_de, 0, 4) AS yy, SUM(tot) AS tot FROM RQTY_DATA_LIST GROUP BY SUBSTR(stdr_de, 0, 4) ) C WHERE YEAR_LIST.yy = B.yy(+) AND YEAR_LIST.yy = C.yy(+) ORDER BY YEAR_LIST.yy ) SELECT yy AS inqire_de, iem_div_id, TO_CHAR(inqire_iem_vu, 'FM999,999,990.0') AS inqire_iem_vu FROM ( SELECT yy, dsqty_sum, rqty_sum, acmtrt FROM DATA_LIST ) UNPIVOT ( inqire_iem_vu FOR iem_div_id IN ( dsqty_sum AS 'dsqtySum', rqty_sum AS 'rqtySum', acmtrt AS 'acmtrt' ) )

/* DSBRD_PC_Dao_retrieveEpwrEnergyOperSttusList */ WITH MONTH_LIST AS ( SELECT /*+ MATERIALZE */ TO_CHAR(ADD_MONTHS(TO_DATE(SUBSTR(#{strtDt}, 0, 6), 'yyyyMM'), LEVEL - 1), 'yyyyMM') AS mt FROM DUAL CONNECT BY LEVEL <= MONTHS_BETWEEN(TO_DATE(SUBSTR(#{endDt}, 0, 6), 'yyyyMM'), TO_DATE(SUBSTR(#{strtDt}, 0, 6), 'yyyyMM')) + 1 ), PRDCTN_DATA_LIST AS ( SELECT /*+ MATERIALZE */ LST.mt, DECODE(LST.elcpwstn_cls_cd, '0005', '0004', LST.elcpwstn_cls_cd) AS elcpwstn_cls_cd, CASE WHEN MAX(LST.elcpwstn_cls_nm) = '한전거래' THEN '태양광' ELSE MAX(LST.elcpwstn_cls_nm) END AS elcpwstn_cls_nm, LST.elcpwstn_cd, CASE WHEN MAX(LST.elcpwstn_cls_nm) = '한전거래' THEN MAX(LST.elcpwstn_nm) || '(한전거래)' ELSE MAX(LST.elcpwstn_nm) END AS elcpwstn_nm, MAX(LST.hq_cd) AS hq_cd, MAX(LST.cstct_vu) AS cstct_vu, MAX(LST.cstct_nm) AS cstct_nm, MAX(LST.elcpwstn_cpcty) AS elcpwstn_cpcty, ROUND(NVL(SUM(LST.r2val), 0), 0) AS r2, MAX(dsply_ordr) AS dsply_ordr FROM ( SELECT /*+ LEADING(BASE LT2 MONTH_LIST) */ MONTH_LIST.mt, BASE.elcpwstn_nm, BASE.elcpwstn_cd, BASE.centr_elyrs_yn, LT2.elyrs_plan_qy / 1000 / 1000 AS r2val, /* W / 1000 / 1000 => MW */ BASE.hq_cd, BASE.cstct_vu, BASE.cstct_nm, BASE.elcpwstn_cls_cd, BASE.elcpwstn_cls_nm, BASE.elcpwstn_cpcty, BASE.dsply_ordr FROM MONTH_LIST, ( SELECT elcpwstn_cd, elcpwstn_nm, DECODE(centr_elyrs_yn, 'X', 'N', centr_elyrs_yn ) AS centr_elyrs_yn, AS hq_cd, cstct_vu, ( SELECT stext FROM HRM.vm_hr01a01 WHERE SYSDATE BETWEEN strdt AND enddt AND objid IN ( SELECT DISTINCT CASE WHEN MIN(depth) OVER(PARTITION BY kostl) = depth THEN objid ELSE NULL END FROM HRM.vm_hr01a01 WHERE SYSDATE BETWEEN strdt AND enddt AND TRIM(kostl) IS NOT NULL ) AND kostl = LPAD(cstct_vu, 10, '0') ) AS cstct_nm, elcpwstn_cls_cd, ( SELECT DECODE(cmmn_cd, '0004', '태양광', '0005', '태양광', '0007', '보소수력', cmmn_cd_nm ) AS cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'WRO' AND cls_cd = 'WRO_3003' AND cmmn_cd = elcpwstn_cls_cd ) AS elcpwstn_cls_nm, elcpwstn_cpcty, accnut_acnt_cd, dsply_ordr FROM WRO.tc_eg10101 WHERE IN ( SELECT objid FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsBasinDivCd}
) AND centr_elyrs_yn IN ('Y', 'N', 'X') AND accnut_acnt_cd LIKE '' || '%' ) BASE, ( SELECT stdr_de, elcpwstn_cd, ROUND(elyrs_plan_qy, 2) AS elyrs_plan_qy, ROUND(excclc_amt, 2) AS excclc_amt FROM ( SELECT SUBSTR(stdr_de, 0, 6) AS stdr_de, elcpwstn_cd, SUM(elyrs_qy) AS elyrs_plan_qy, SUM(excclc_amt) AS excclc_amt FROM WRO.tm_eg04105 WHERE stdr_de BETWEEN SUBSTR(#{strtDt}, 0, 6) || '01' AND SUBSTR(#{endDt}, 0, 6) || '31' AND excclc_div_cd = '0001' GROUP BY SUBSTR(stdr_de, 0, 6), elcpwstn_cd UNION ALL SELECT SUBSTR(stdr_plan_ym, 0, 6) AS stdr_plan_ym, elcpwstn_cd, SUM(elyrs_qy) * 1000 AS elyrs_plan_qy, SUM(splval_amt) AS excclc_amt FROM WRO.tm_eg04117 WHERE stdr_plan_ym BETWEEN SUBSTR(#{strtDt}, 0, 6) AND SUBSTR(#{endDt}, 0, 6) GROUP BY SUBSTR(stdr_plan_ym, 0, 6), elcpwstn_cd ) ) LT2 WHERE BASE.elcpwstn_cd = LT2.elcpwstn_cd(+) AND MONTH_LIST.mt = LT2.stdr_de(+) ) LST GROUP BY LST.mt, LST.elcpwstn_cls_cd, LST.elcpwstn_cd ), CNSTN_DATA_INIT_LIST AS ( SELECT /*+ MATERIALZE LEADING(BBB AAA) */ AS dscfc_lclhq_cd, ( SELECT cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'SC' AND cls_cd = 'GHG_1001' AND cmmn_cd = ) AS dscfc_lclhq_nm, BBB.dscfc_bplc_cd, ( SELECT cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'SC' AND cls_cd = 'GHG_1002' AND cmmn_cd = BBB.dscfc_bplc_cd ) AS dscfc_bplc_nm, DECODE(BBB.dscfc_procs_ty_cd, '01', '01', '02', '02', '03', '03', '99') AS dscfc_procs_ty_cd, ( SELECT B.cmmn_cd_nm FROM ( SELECT cmmn_cd, cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'SC' AND cls_cd = 'GHG_0024' ) A, ( SELECT usr_dfn_vu2, cmmn_cd_nm FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_1003' ) B WHERE A.cmmn_cd = B.usr_dfn_vu2 AND A.cmmn_cd = DECODE(BBB.dscfc_procs_ty_cd, '01', '01', '02', '02', '03', '03', '99') ) AS dscfc_procs_ty_nm, BBB.dscfc_use_fuel_div_cd, AAA.sum_dscfc_usgqty, AAA.dscfc_use_de FROM GHG.tm_gg01101 BBB, ( SELECT ABC.dscfc_id, ABC.dscfc_use_de, MAX(ABC.usgqty) AS sum_dscfc_usgqty FROM ( SELECT AA.dscfc_id, AA.dscfc_use_de, CASE WHEN AA.dsqty_cfrml_parm_id IN ('2005', '2001') THEN MAX(AA.dscfc_usgqty) END AS usgqty FROM ( SELECT /*+ LEADING(B A) */ A.dscfc_id, A.dscfc_use_de, B.dsqty_cfrml_parm_id, B.dsqty_cfrml_parm_nm, A.dscfc_usgqty FROM GHG.tm_rq01103 A, GHG.tm_gg01104 B WHERE ( (A.dscfc_use_slip_no IS NOT NULL AND A.dscfc_use_slip_no NOT LIKE 'TMP%') OR A.dscfc_use_slip_prcs_ty_cd = '1' ) AND A.dsqty_cfrml_parm_id IN ('2005', '2001') AND A.dscfc_use_de BETWEEN ( SELECT MIN(mt) FROM MONTH_LIST ) || '01' AND ( SELECT MAX(mt) FROM MONTH_LIST ) || '31' AND A.dsqty_cfrml_parm_id = B.dsqty_cfrml_parm_id ) AA GROUP BY AA.dscfc_id, AA.dscfc_use_de, AA.dsqty_cfrml_parm_id, AA.dsqty_cfrml_parm_nm ) ABC GROUP BY ABC.dscfc_id, ABC.dscfc_use_de ) AAA WHERE BBB.dscfc_id = AAA.dscfc_id(+) AND BBB.dscfc_use_yn = '1' AND BBB.dscfc_regist_stat_div_cd = '1' AND BBB.dscfc_use_fuel_div_cd = '61' /* 전기 */ AND BBB.dscfc_lclhq_cd != '88888888' /* 위탁 */ ), CNSTN_DATA_LIST AS ( SELECT /*+ MATERIALZE LEADING(CNSTN_DATA_INIT_LIST MONTH_LIST) */ MONTH_LIST.mt, MAX(CNSTN_DATA_INIT_LIST.dscfc_procs_ty_nm) AS dscfc_procs_ty_nm, MAX(CNSTN_DATA_INIT_LIST.dscfc_lclhq_nm) AS dscfc_lclhq_nm, ROUND(NVL(SUM(CNSTN_DATA_INIT_LIST.sum_dscfc_usgqty / 1000), 0), 2) AS sum_dscfc_usgqty /* kW / 1000 => MW */ FROM MONTH_LIST, CNSTN_DATA_INIT_LIST WHERE MONTH_LIST.mt = SUBSTR(CNSTN_DATA_INIT_LIST.dscfc_use_de(+), 0, 6) AND IN ( SELECT objid FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsBasinDivCd}
) AND dscfc_use_de IS NOT NULL GROUP BY MONTH_LIST.mt, CNSTN_DATA_INIT_LIST.dscfc_lclhq_cd, CNSTN_DATA_INIT_LIST.dscfc_procs_ty_cd ORDER BY mt, dscfc_procs_ty_cd, dscfc_lclhq_cd ) SELECT mt AS inqire_de, 'prdctn' AS iem_div_id, SUM(r2) AS inqire_iem_vu FROM PRDCTN_DATA_LIST GROUP BY mt UNION ALL SELECT mt AS inqire_de, 'cnstn' AS iem_div_id, SUM(sum_dscfc_usgqty) AS inqire_iem_vu FROM CNSTN_DATA_LIST GROUP BY mt ORDER BY inqire_de, iem_div_id

/* DSBRD_PC_Dao_retrievePrdctnEpwrList */ WITH MONTH_LIST AS ( SELECT /*+ MATERIALZE */ TO_CHAR(ADD_MONTHS(TO_DATE(SUBSTR(#{strtDt}, 0, 6), 'yyyyMM'), LEVEL - 1), 'yyyyMM') AS mt FROM DUAL CONNECT BY LEVEL <= MONTHS_BETWEEN(TO_DATE(SUBSTR(#{endDt}, 0, 6), 'yyyyMM'), TO_DATE(SUBSTR(#{strtDt}, 0, 6), 'yyyyMM')) + 1 ), WTHT_MAPPING_LIST AS ( SELECT /*+ MATERIALZE */ SUBSTR(mt, 0, 4) AS yy, ( SELECT usr_dfn_vu1 FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_1001' AND usr_dfn_vu3 LIKE '%01%' AND cmmn_cd = '60' /* 수열 */ ) AS iem_div_id FROM MONTH_LIST GROUP BY SUBSTR(mt, 0, 4) ), WTHT_INIT_DATA_LIST1 AS ( SELECT /*+ MATERIALZE */ ecs_chrg_dept_id, wtht_suply_begin_de, eqp_nm FROM tm_cl12001 WHERE iem_div_nm = '03' /* 외부 */ ), WTHT_INIT_DATA_LIST2 AS ( SELECT /*+ MATERIALZE */ wtht_suply_begin_de, eqp_nm, ctrpd_end_de, excclc_amt FROM tm_cl12002 WHERE ctrpd_end_de BETWEEN ( SELECT MIN(mt) FROM MONTH_LIST ) || '01' AND ( SELECT MAX(mt) FROM MONTH_LIST ) || '31' ), WTHT_DATA_LIST AS ( SELECT /*+ MATERIALZE LEADING(WTHT_MAPPING_LIST A) */ WTHT_MAPPING_LIST.yy, WTHT_MAPPING_LIST.iem_div_id, NVL(A.excclc_amt, 0) AS inqire_iem_vu FROM WTHT_MAPPING_LIST, ( SELECT /*+ LEADING(A WTHT_INIT_DATA_LIST2) */ SUBSTR(WTHT_INIT_DATA_LIST2.ctrpd_end_de, 0, 4) AS yy, SUM(WTHT_INIT_DATA_LIST2.excclc_amt) AS excclc_amt FROM ( SELECT ecs_chrg_dept_id, wtht_suply_begin_de, eqp_nm FROM WTHT_INIT_DATA_LIST1 WHERE 1 = 1
AND ecs_chrg_dept_id IN ( SELECT obj FROM ( SELECT upobj AS objid, objid AS obj FROM (
) ) WHERE IN ( SELECT objid FROM (
) WHERE cmmn_cd = #{ecsBasinDivCd} ) )
) A, WTHT_INIT_DATA_LIST2 WHERE A.wtht_suply_begin_de = WTHT_INIT_DATA_LIST2.wtht_suply_begin_de(+) AND A.eqp_nm = WTHT_INIT_DATA_LIST2.eqp_nm(+) GROUP BY SUBSTR(WTHT_INIT_DATA_LIST2.ctrpd_end_de, 0, 4) ) A WHERE WTHT_MAPPING_LIST.yy = A.yy(+) ), PRDCTN_DATA_INIT_LIST AS ( SELECT /*+ MATERIALZE */ mt, hq_cd, sap_bplc_vu, elcpwstn_cls_nm, elcpwstn_cd, elcpwstn_nm, s2, /* 계획 전력거래량(전력생산량) */ s3, /* 계획 발전수익 */ r2, /* 실적 전력거래량(전력생산량) */ r3, /* 실적 발전수익 */ NVL(t2, 0) AS t2, /* 계획 대비 실적 전력거래량 */ NVL(t3, 0) AS t3, /* 계획 대비 실적 발전수익 */ CASE WHEN s2 > 0 AND s3 > 0 THEN ROUND(s3 / (s2 * 1000), 2) ELSE 0 END AS s4, /* 계획 판매단가 */ CASE WHEN r2 > 0 AND r3 > 0 THEN ROUND(r3 / (r2 * 1000), 2) ELSE 0 END AS r4, /* 실적 판매단가 */ DECODE('01', 0, 0, ROUND(r2 / ('01' * 24 * NULLIF(elcpwstn_cpcty, 0) * 10), 2) ) AS c1, /* 이용률 */ dsply_ordr FROM ( SELECT LST.mt, DECODE(LST.elcpwstn_cls_cd, '0005', '0004', LST.elcpwstn_cls_cd) AS elcpwstn_cls_cd, CASE WHEN MAX(LST.elcpwstn_cls_nm) = '한전거래' THEN '태양광' ELSE MAX(LST.elcpwstn_cls_nm) END AS elcpwstn_cls_nm, LST.elcpwstn_cd, CASE WHEN MAX(LST.elcpwstn_cls_nm) = '한전거래' THEN MAX(LST.elcpwstn_nm) || '(한전거래)' ELSE MAX(LST.elcpwstn_nm) END AS elcpwstn_nm, MAX(LST.hq_cd) AS hq_cd, MAX(LST.sap_bplc_vu) AS sap_bplc_vu, MAX(LST.cstct_vu) AS cstct_vu, MAX(LST.cstct_nm) AS cstct_nm, MAX(LST.elcpwstn_cpcty) AS elcpwstn_cpcty, ROUND(NVL(SUM(LST.s2val), 0), 2) AS s2, ROUND(NVL(SUM(LST.s3val), 0), 2) AS s3, ROUND(NVL(SUM(LST.r2val), 0), 2) AS r2, ROUND(NVL(SUM(LST.r3val + NVL(MPF.epwr_indust_fnd_fund_amt, 0)), 0) - NVL(SUM(HST.etc_dstb_profit_amt), 0), 2) AS r3, DECODE(SUM(LST.s2val), 0, 0, ROUND((NVL(SUM(LST.r2val), 0) / SUM(LST.s2val)) * 100, 2) ) AS t2, DECODE(SUM(LST.s3val), 0, 0, ROUND((NVL(SUM(LST.r3val + NVL(MPF.epwr_indust_fnd_fund_amt, 0)), 0) / SUM(LST.s3val)) * 100, 2) ) AS t3, MAX(dsply_ordr) AS dsply_ordr FROM ( SELECT MONTH_LIST.mt, BASE.elcpwstn_nm, BASE.elcpwstn_cd, BASE.centr_elyrs_yn, LT1.elyrs_plan_qy AS s2val, /* MW */ LT3.expect_ern_upc * 1000 AS s3val, LT2.elyrs_plan_qy / 1000 / 1000 AS r2val, /* W / 1000 / 1000 => MW */ DECODE(BASE.centr_elyrs_yn, 'N', NVL(LT4.sep_amt, LT2.excclc_amt), DECODE(LT2.excclc_amt, '', LT4.excclc_amt, DECODE(LT2.excclc_amt, 0, LT4.excclc_amt, LT2.excclc_amt ) ) ) AS r3val, BASE.hq_cd, BASE.sap_bplc_vu, BASE.cstct_vu, BASE.cstct_nm, BASE.elcpwstn_cls_cd, BASE.elcpwstn_cls_nm, BASE.elcpwstn_cpcty, BASE.dsply_ordr FROM MONTH_LIST, ( SELECT elcpwstn_cd, elcpwstn_nm, DECODE(centr_elyrs_yn, 'X', 'N', centr_elyrs_yn ) AS centr_elyrs_yn, AS hq_cd, sap_bplc_vu, cstct_vu, ( SELECT stext FROM HRM.vm_hr01a01 WHERE SYSDATE BETWEEN strdt AND enddt AND objid IN ( SELECT DISTINCT CASE WHEN MIN(depth) OVER(PARTITION BY kostl) = depth THEN objid ELSE NULL END FROM HRM.vm_hr01a01 WHERE SYSDATE BETWEEN strdt AND enddt AND TRIM(kostl) IS NOT NULL ) AND kostl = LPAD(cstct_vu, 10, '0') ) AS cstct_nm, elcpwstn_cls_cd, ( SELECT DECODE(cmmn_cd, '0004', '태양광', '0005', '태양광', '0007', '보소수력', cmmn_cd_nm ) AS cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'WRO' AND cls_cd = 'WRO_3003' AND cmmn_cd = elcpwstn_cls_cd ) AS elcpwstn_cls_nm, elcpwstn_cpcty, accnut_acnt_cd, dsply_ordr FROM WRO.tc_eg10101 WHERE centr_elyrs_yn IN ('Y', 'N', 'X') AND accnut_acnt_cd LIKE '' || '%' AND IN ( SELECT objid FROM (
) WHERE 1 = 1 ) ) BASE, ( SELECT stdr_plan_ym, elcpwstn_cd, ROUND(SUM(elyrs_plan_qy), 2) AS elyrs_plan_qy FROM ( SELECT stdr_plan_ym, elcpwstn_cd, SUM(elyrs_plan_qy) AS elyrs_plan_qy FROM WRO.tc_eg10112 WHERE stdr_plan_ym BETWEEN SUBSTR(#{strtDt}, 0, 6) AND SUBSTR(#{endDt}, 0, 6) GROUP BY stdr_plan_ym, elcpwstn_cd /* UNION ALL SELECT elcpwstn_cd, (SUM(elyrs_plan_qy) / '99') * '01' AS elyrs_plan_qy FROM WRO.tc_eg10112 WHERE stdr_plan_ym = '299999' GROUP BY elcpwstn_cd */ ) GROUP BY stdr_plan_ym, elcpwstn_cd ) LT1, ( SELECT stdr_de, elcpwstn_cd, ROUND(elyrs_plan_qy, 2) AS elyrs_plan_qy, ROUND(excclc_amt, 2) AS excclc_amt FROM ( SELECT SUBSTR(stdr_de, 0, 6) AS stdr_de, elcpwstn_cd, SUM(elyrs_qy) AS elyrs_plan_qy, SUM(excclc_amt) AS excclc_amt FROM WRO.tm_eg04105 WHERE excclc_div_cd = '0001' /* 자체 */ AND stdr_de BETWEEN SUBSTR(#{strtDt}, 0, 6) || '01' AND SUBSTR(#{endDt}, 0, 6) || '31' GROUP BY SUBSTR(stdr_de, 0, 6), elcpwstn_cd UNION ALL SELECT SUBSTR(stdr_plan_ym, 0, 6) AS stdr_plan_ym, elcpwstn_cd, SUM(elyrs_qy) * 1000 AS elyrs_plan_qy, SUM(splval_amt) AS excclc_amt FROM WRO.tm_eg04117 WHERE stdr_plan_ym BETWEEN SUBSTR(#{strtDt}, 0, 6) AND SUBSTR(#{endDt}, 0, 6) GROUP BY SUBSTR(stdr_plan_ym, 0, 6), elcpwstn_cd ) ) LT2, ( SELECT stdr_plan_ym, elcpwstn_cd, ROUND(SUM(expect_ern_upc), 2) AS expect_ern_upc FROM ( SELECT SUBSTR(stdr_plan_ym, 0, 6) AS stdr_plan_ym, elcpwstn_cd, SUM(expect_ern_upc_vu) AS expect_ern_upc FROM WRO.tm_eg01104 WHERE stdr_plan_ym BETWEEN SUBSTR(#{strtDt}, 0, 6) AND SUBSTR(#{endDt}, 0, 6) GROUP BY SUBSTR(stdr_plan_ym, 0, 6), elcpwstn_cd /* UNION ALL SELECT elcpwstn_cd, (SUM(expect_ern_upc_vu) / '99') * '01' AS expect_ern_upc FROM WRO.tm_eg01104 WHERE stdr_plan_ym = '299999' GROUP BY elcpwstn_cd */ ) GROUP BY stdr_plan_ym, elcpwstn_cd ) LT3, ( SELECT SUBSTR(stdr_de, 0, 6) AS stdr_de, elcpwstn_cd, ROUND(SUM(sep_amt), 2) AS sep_amt, ROUND(SUM(excclc_sum_amt), 2) AS excclc_amt FROM WRO.tm_eg03121 WHERE excclc_div_cd = '0001' AND stdr_de BETWEEN SUBSTR(#{strtDt}, 0, 6) || '01' AND SUBSTR(#{endDt}, 0, 6) || '31' GROUP BY SUBSTR(stdr_de, 0, 6), elcpwstn_cd ) LT4 WHERE BASE.elcpwstn_cd = LT1.elcpwstn_cd(+) AND BASE.elcpwstn_cd = LT2.elcpwstn_cd(+) AND BASE.elcpwstn_cd = LT3.elcpwstn_cd(+) AND BASE.elcpwstn_cd = LT4.elcpwstn_cd(+) AND MONTH_LIST.mt = LT1.stdr_plan_ym(+) AND MONTH_LIST.mt = LT2.stdr_de(+) AND MONTH_LIST.mt = LT3.stdr_plan_ym(+) AND MONTH_LIST.mt = LT4.stdr_de(+) ) LST, ( SELECT SUBSTR(stdr_plan_ym, 0, 6) AS stdr_plan_ym, elcpwstn_cd, ROUND(SUM(etc_dstb_profit_amt), 2) AS etc_dstb_profit_amt FROM WRO.tm_eg05115 WHERE stdr_plan_ym BETWEEN SUBSTR(#{strtDt}, 0, 6) AND SUBSTR(#{endDt}, 0, 6) GROUP BY SUBSTR(stdr_plan_ym, 0, 6), elcpwstn_cd ) HST, ( SELECT SUBSTR(stdr_de, 0, 6) AS stdr_de, elcpwstn_cd, ROUND(TRUNC(SUM(TO_NUMBER(epwr_indust_fnd_fund_amt)) - TO_NUMBER(TRUNC(SUM(epwr_indust_fnd_rdcamt_vu), -1)), -1), 2) AS epwr_indust_fnd_fund_amt FROM WRO.tm_eg05106 WHERE stdr_de BETWEEN SUBSTR(#{strtDt}, 0, 6) || '01' AND SUBSTR(#{endDt}, 0, 6) || '31' GROUP BY SUBSTR(stdr_de, 0, 6), elcpwstn_cd ) MPF WHERE LST.elcpwstn_cd = HST.elcpwstn_cd(+) AND LST.elcpwstn_cd = MPF.elcpwstn_cd(+) AND LST.mt = HST.stdr_plan_ym(+) AND LST.mt = MPF.stdr_de(+) GROUP BY LST.mt, LST.elcpwstn_cls_cd, LST.elcpwstn_cd ) ) SELECT inqire_de, iem_div_id, inqire_iem_vu FROM ( SELECT SUBSTR(mt, 0, 4) AS inqire_de, ROUND(SUM(r2) / 1000, 2) AS prdctn_total_acmslt, /* MW / 1000 => GW */ ROUND(SUM(s2) / 1000, 2) AS prdctn_total_plan, /* MW / 1000 => GW */ CASE WHEN NVL(SUM(r2), 0) > 0 AND NVL(SUM(s2), 0) > 0 THEN ROUND((SUM(r2) / SUM(s2)) * 100, 2) ELSE 0 END AS prdctn_total_cmpr, /* ROUND(AVG(t2), 2) AS prdctn_total_cmpr, */ /* ROUND(AVG(s4), 2) AS elyrs_upc_plan, */ CASE WHEN SUM(r2) > 0 AND SUM(r3) > 0 THEN ROUND(SUM(r3) / SUM(r2) / 1000, 2) ELSE 0 END AS elyrs_upc_acmslt, /* 실적 판매단가 */ /* CASE WHEN AVG(r4) > 0 AND AVG(s4) > 0 THEN ROUND(AVG(r4) / AVG(s4) * 100, 2) ELSE 0 END AS elyrs_upc_cmpr, */ ROUND(((SUM(r3) + (SELECT inqire_iem_vu FROM WTHT_DATA_LIST WHERE yy = SUBSTR(mt, 0, 4))) / 1000 / 1000 / 100) * 1.1, 2) AS prdctn_excclc_total /* 원 / 1000 / 1000 / 100 => 억원 */ FROM ( SELECT mt, hq_cd, elcpwstn_cls_nm, elcpwstn_cd, elcpwstn_nm, s2, s3, r2, r3, t2, t3, s4, r4, c1, dsply_ordr FROM PRDCTN_DATA_INIT_LIST WHERE IN ( SELECT objid FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsBasinDivCd}
) AND mt BETWEEN SUBSTR(#{strtDt}, 0, 4) || '01' AND SUBSTR(#{endDt}, 0, 4) || '12' ) GROUP BY SUBSTR(mt, 0, 4) ) UNPIVOT (inqire_iem_vu FOR iem_div_id IN ( prdctn_total_acmslt AS 'prdctnTotalAcmslt', prdctn_total_plan AS 'prdctnTotalPlan', prdctn_total_cmpr AS 'prdctnTotalCmpr',
elyrs_upc_acmslt AS 'elyrsUpcAcmslt',
prdctn_excclc_total AS 'prdctnExcclcTotal' ) ) ORDER BY inqire_de, iem_div_id

/* DSBRD_PC_Dao_retrieveCnstnEpwrList */ WITH MONTH_LIST AS ( SELECT /*+ MATERIALZE */ TO_CHAR(ADD_MONTHS(TO_DATE(SUBSTR(#{strtDt}, 0, 6), 'yyyyMM'), LEVEL - 1), 'yyyyMM') AS mt FROM DUAL CONNECT BY LEVEL <= MONTHS_BETWEEN(TO_DATE(SUBSTR(#{endDt}, 0, 6), 'yyyyMM'), TO_DATE(SUBSTR(#{strtDt}, 0, 6), 'yyyyMM')) + 1 ), USWTR_SQTY_MAPPING_LIST AS ( SELECT /*+ MATERIALZE LEADING(BASIN DEPT BPLC USWTR_SQTY_MONTH_LIST) */ MONTH_LIST.mt, BASIN.cmmn_cd AS basin_cd, BASIN.cmmn_cd_nm AS basin_nm, BASIN.sort_ordr AS basin_sort, DEPT.cmmn_cd AS dept_cd, DEPT.cmmn_cd_nm AS dept_nm, DEPT.sort_ordr AS dept_sort, BPLC.cmmn_cd AS bplc_cd, BPLC.cmmn_cd_nm AS bplc_nm, BPLC.sort_ordr AS bplc_sort, USWTR_SQTY.cmmn_cd AS uswtr_sqty_cd, USWTR_SQTY.cmmn_cd_nm AS uswtr_sqty_nm, USWTR_SQTY.disc_fclty_no AS uswtr_sqty_disc_fclty_no, USWTR_SQTY.anlrpt_bplc_no AS uswtr_sqty_anlrpt_bplc_no, USWTR_SQTY.anlrpt_bplc_seq AS uswtr_sqty_anlrpt_bplc_seq, USWTR_SQTY.sort_ordr AS uswtr_sqty_sort FROM ( SELECT cls_cd, cmmn_cd, cmmn_cd_nm, upper_cls_cd, upper_cmmn_cd, sort_ordr FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_1000' ) BASIN, ( SELECT cls_cd, cmmn_cd, cmmn_cd_nm, upper_cls_cd, upper_cmmn_cd, sort_ordr FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_2001' ) DEPT, ( SELECT cls_cd, cmmn_cd, cmmn_cd_nm, upper_cls_cd, upper_cmmn_cd, usr_dfn_vu1, sort_ordr FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_2002' AND usr_dfn_vu2 != 'N' ) BPLC, ( SELECT A.cmmn_cd, MAX(A.cmmn_cd_nm) AS cmmn_cd_nm, MAX(A.upper_cls_cd) AS upper_cls_cd, MAX(A.upper_cmmn_cd) AS upper_cmmn_cd, /* ( SELECT fnct_lc_dtls FROM WFM.tm_zc10001 WHERE fnct_lc_no = A.cmmn_cd ) AS bplc_fnct_lc_nm, */ MAX(B.disc_fclty_no) AS disc_fclty_no, MAX(B.dstrct_hq_cd) AS dstrct_hq_cd, MAX(B.plnt_no) AS plnt_no, C.anlrpt_bplc_no, C.anlrpt_bplc_seq, MAX(A.sort_ordr) AS sort_ordr FROM ( SELECT cmmn_cd, cmmn_cd_nm, upper_cls_cd, upper_cmmn_cd, sort_ordr FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_2010' ) A, WRO.ti_pg20058 B, WRO.ti_pg20060 C WHERE A.cmmn_cd = B.bplc_fnct_lc_no AND B.bplc_fnct_lc_no = C.bplc_fnct_lc_no GROUP BY A.cmmn_cd, C.anlrpt_bplc_no, C.anlrpt_bplc_seq ) USWTR_SQTY, MONTH_LIST WHERE USWTR_SQTY.upper_cls_cd(+) = BPLC.cls_cd AND USWTR_SQTY.upper_cmmn_cd(+) = BPLC.cmmn_cd AND BPLC.upper_cls_cd = DEPT.cls_cd AND BPLC.upper_cmmn_cd = DEPT.cmmn_cd AND DEPT.upper_cls_cd = BASIN.cls_cd AND DEPT.upper_cmmn_cd = BASIN.cmmn_cd ORDER BY basin_sort, dept_sort, bplc_sort, uswtr_sqty_sort ), USWTR_SQTY_DATA_LIST AS ( SELECT /*+ MATERIALZE LEADING(A B) */ B.mt, A.bplc_cd, A.bplc_nm, A.dept_cd, A.uswtr_sqty_disc_fclty_no, A.uswtr_sqty_nm, B.dail_bplc_sqty AS uswtr_sqty FROM ( SELECT uswtr_sqty_cd, MAX(bplc_cd) AS bplc_cd, MAX(bplc_nm) AS bplc_nm, MAX(dept_cd) AS dept_cd, MAX(uswtr_sqty_disc_fclty_no) AS uswtr_sqty_disc_fclty_no, uswtr_sqty_anlrpt_bplc_no AS uswtr_sqty_anlrpt_bplc_no, MAX(uswtr_sqty_nm) AS uswtr_sqty_nm FROM USWTR_SQTY_MAPPING_LIST GROUP BY uswtr_sqty_cd, uswtr_sqty_anlrpt_bplc_no ) A, ( SELECT SUBSTR(suply_de, 0, 6) AS mt, anlrpt_bplc_no, ROUND(NVL(SUM(dail_bplc_sqty), 0), 0) AS dail_bplc_sqty FROM WRO.ts_pge4901 WHERE suply_de BETWEEN ( SELECT MIN(mt) FROM MONTH_LIST ) || '01' AND ( SELECT MAX(mt) FROM MONTH_LIST ) || '31' AND (anlrpt_bplc_no, anlrpt_bplc_seq) IN ( SELECT DISTINCT uswtr_sqty_anlrpt_bplc_no, uswtr_sqty_anlrpt_bplc_seq FROM USWTR_SQTY_MAPPING_LIST WHERE USWTR_SQTY_ANLRPT_BPLC_NO IS NOT NULL ) GROUP BY SUBSTR(suply_de, 0, 6), anlrpt_bplc_no ) B WHERE A.uswtr_sqty_anlrpt_bplc_no = B.anlrpt_bplc_no ), CNSTN_DATA_INIT_LIST AS ( SELECT /*+ MATERIALZE LEADING(BBB AAA CCC) */ BBB.dscfc_id, BBB.dscfc_nm, AS dscfc_lclhq_cd, ( SELECT cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'SC' AND cls_cd = 'GHG_1001' AND cmmn_cd = ) AS dscfc_lclhq_nm, BBB.dscfc_bplc_cd, ( SELECT cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'SC' AND cls_cd = 'GHG_1002' AND cmmn_cd = BBB.dscfc_bplc_cd ) AS dscfc_bplc_nm, BBB.dscfc_procs_ty_cd, ( SELECT B.cmmn_cd_nm FROM ( SELECT cmmn_cd, cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'SC' AND cls_cd = 'GHG_0024' ) A, ( SELECT usr_dfn_vu2, cmmn_cd_nm FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_1003' ) B WHERE A.cmmn_cd = B.usr_dfn_vu2 AND A.cmmn_cd = BBB.dscfc_procs_ty_cd ) AS dscfc_procs_ty_nm, BBB.dscfc_use_fuel_div_cd, AAA.dscfc_use_de, AAA.dscfc_use_slip_prcs_ty_cd, AAA.dscfc_use_slip_no, NVL(AAA.tot_amt, 0) AS tot_amt, MAX(NVL(AAA.tot_amt, 0)) OVER(PARTITION BY AAA.dscfc_use_slip_no) AS max_tot_amt, NVL(AAA.dscfc_usgqty, 0) AS dscfc_usgqty, SUM(NVL(AAA.dscfc_usgqty, 0)) OVER(PARTITION BY AAA.dscfc_use_slip_no) AS sum_dscfc_usgqty, COUNT(AAA.dscfc_use_slip_no) OVER(PARTITION BY AAA.dscfc_use_slip_no) AS count_dscfc_use_slip_no, MAX(NVL(ABS(AAA.dscfc_usgqty), 0)) OVER(PARTITION BY AAA.dscfc_use_slip_no) AS max_abs_dscfc_usgqty FROM GHG.tm_gg01101 BBB, ( SELECT ABC.dscfc_id, ABC.dscfc_use_de, MAX(ABC.dscfc_use_slip_prcs_ty_cd) AS dscfc_use_slip_prcs_ty_cd, MAX(ABC.dscfc_use_slip_no) AS dscfc_use_slip_no, NVL(MAX(ABC.tot_amt), 0) AS tot_amt, NVL(MAX(ABC.dscfc_usgqty), 0) AS dscfc_usgqty FROM ( SELECT AA.dscfc_id, AA.dscfc_use_de, MAX(AA.dscfc_use_slip_prcs_ty_cd) AS dscfc_use_slip_prcs_ty_cd, MAX(AA.dscfc_use_slip_no) AS dscfc_use_slip_no, CASE WHEN AA.dsqty_cfrml_parm_id IN ('2005', '2001') THEN MAX(AA.tot_amt) END AS tot_amt, CASE WHEN AA.dsqty_cfrml_parm_id IN ('2005', '2001') THEN MAX(AA.dscfc_usgqty) END AS dscfc_usgqty FROM ( SELECT /*+ LEADING(B A) */ A.dscfc_id, A.dscfc_use_de, B.dsqty_cfrml_parm_id, B.dsqty_cfrml_parm_nm, A.dscfc_use_slip_prcs_ty_cd, A.dscfc_use_slip_no, A.tot_amt, A.dscfc_usgqty FROM GHG.tm_rq01103 A, GHG.tm_gg01104 B WHERE ( (A.dscfc_use_slip_no IS NOT NULL AND A.dscfc_use_slip_no NOT LIKE 'TMP%') OR A.dscfc_use_slip_prcs_ty_cd = '1' ) AND A.dsqty_cfrml_parm_id IN ('2005', '2001') AND A.dscfc_use_de BETWEEN SUBSTR(#{strtDt}, 0, 6) || '01' AND SUBSTR(#{endDt}, 0, 6) || '31' AND A.dsqty_cfrml_parm_id = B.dsqty_cfrml_parm_id ) AA GROUP BY AA.dscfc_id, AA.dscfc_use_de, AA.dsqty_cfrml_parm_id, AA.dsqty_cfrml_parm_nm ) ABC GROUP BY ABC.dscfc_id, ABC.dscfc_use_de ) AAA WHERE BBB.dscfc_id = AAA.dscfc_id(+) AND BBB.dscfc_use_yn = '1' AND BBB.dscfc_regist_stat_div_cd = '1' AND BBB.dscfc_use_fuel_div_cd = '61' /* 전기 */ AND BBB.dscfc_lclhq_cd != '88888888' /* 위탁 */ AND AAA.dscfc_use_de IS NOT NULL ), CNSTN_DATA_LIST AS ( SELECT /*+ MATERIALZE */ SUBSTR(dscfc_use_de, 0, 4) AS yy, ROUND(NVL(SUM(dscfc_usgqty / 1000), 0), 2) AS cnstn_total, /* kW / 1000 => MW */ ROUND(NVL(SUM(tot_amt / 1000 / 1000 / 100), 0), 2) AS cnstn_excclc_total /* 원 / 1000 / 1000 / 100 => 억원 */ FROM ( SELECT SUBSTR(dscfc_use_de, 0, 6) AS dscfc_use_de, dscfc_id, SUM(dscfc_usgqty) AS dscfc_usgqty, CASE WHEN SUM(dscfc_usgqty) < 0 AND SUM(tot_amt) > 0 THEN SUM(tot_amt) * -1 ELSE SUM(tot_amt) END AS tot_amt FROM ( SELECT dscfc_use_de, dscfc_id, dscfc_usgqty, CASE WHEN max_abs_dscfc_usgqty = 0 AND count_dscfc_use_slip_no > 1 THEN max_tot_amt / count_dscfc_use_slip_no WHEN dscfc_use_slip_prcs_ty_cd != 0 AND (dscfc_usgqty != 0 OR count_dscfc_use_slip_no > 1) THEN (dscfc_usgqty / DECODE(NVL(sum_dscfc_usgqty, 0), 0, 1, sum_dscfc_usgqty)) * max_tot_amt ELSE tot_amt END AS tot_amt FROM CNSTN_DATA_INIT_LIST WHERE IN ( SELECT objid FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsBasinDivCd}
) AND SUBSTR(dscfc_use_de, 0, 4) BETWEEN SUBSTR(#{strtDt}, 0, 4) AND SUBSTR(#{endDt}, 0, 4) ) GROUP BY SUBSTR(dscfc_use_de, 0, 6), dscfc_id ) GROUP BY SUBSTR(dscfc_use_de, 0, 4) ), EPBU_DATA_LIST AS ( SELECT A.yy, A.dscfc_usgqty, /* kW */ B.uswtr_sqty, /* ㎥ */ CASE WHEN B.uswtr_sqty > 0 THEN (A.dscfc_usgqty / B.uswtr_sqty) ELSE NULL END AS epbu FROM ( SELECT SUBSTR(dscfc_use_de, 0, 4) AS yy, SUM(NVL(dscfc_usgqty, 0)) AS dscfc_usgqty FROM CNSTN_DATA_INIT_LIST WHERE IN ( SELECT objid FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsBasinDivCd}
) AND dscfc_procs_ty_cd IN ('01', '02', '03') /* 취수시설, 가압시설, 정수시설 */ AND SUBSTR(dscfc_use_de, 0, 4) BETWEEN SUBSTR(#{strtDt}, 0, 4) AND SUBSTR(#{endDt}, 0, 4) AND dscfc_id IN ( SELECT DISTINCT uswtr_sqty_disc_fclty_no FROM USWTR_SQTY_MAPPING_LIST ) GROUP BY SUBSTR(dscfc_use_de, 0, 4) ) A, ( SELECT SUBSTR(mt, 0, 4) AS yy, SUM(NVL(uswtr_sqty, 0)) AS uswtr_sqty FROM USWTR_SQTY_DATA_LIST GROUP BY SUBSTR(mt, 0, 4) ) B WHERE A.yy = B.yy )
SELECT inqire_de, iem_div_id, inqire_iem_vu FROM ( SELECT yy AS inqire_de, ROUND(cnstn_total / 1000, 2) AS cnstn_total, /* MW / 1000 => GW */ cnstn_excclc_total FROM CNSTN_DATA_LIST ) UNPIVOT (inqire_iem_vu FOR iem_div_id IN ( cnstn_total AS 'cnstnTotal', cnstn_excclc_total AS 'cnstnExcclcTotal' ) ) UNION ALL SELECT yy AS inqire_de, 'epbu' AS iem_div_id, CASE WHEN SUM(uswtr_sqty) > 0 THEN ROUND(NVL(SUM(dscfc_usgqty) / SUM(uswtr_sqty), 0), 4) ELSE NULL END AS inqire_iem_vu FROM EPBU_DATA_LIST GROUP BY yy ORDER BY inqire_de, iem_div_id

/* DSBRD_PC_Dao_retrievePrdctnChartList */ WITH MONTH_LIST AS ( SELECT /*+ MATERIALZE */ TO_CHAR(ADD_MONTHS(TO_DATE(SUBSTR(#{strtDt}, 0, 6), 'yyyyMM'), LEVEL - 1), 'yyyyMM') AS mt FROM DUAL CONNECT BY LEVEL <= MONTHS_BETWEEN(TO_DATE(SUBSTR(#{endDt}, 0, 6), 'yyyyMM'), TO_DATE(SUBSTR(#{strtDt}, 0, 6), 'yyyyMM')) + 1 ) SELECT mt AS inqire_de, MAX(elcpwstn_cls_nm) AS elcpwstn_cls_nm, ( SELECT REPLACE(stext, '본부', '') AS stext FROM (
) WHERE objid = hq_cd ) AS hq_nm, SUM(r2) AS inqire_iem_vu FROM ( SELECT SUBSTR(LST.mt, 0, 4) AS mt, DECODE(LST.elcpwstn_cls_cd, '0005', '0004', LST.elcpwstn_cls_cd) AS elcpwstn_cls_cd, CASE WHEN MAX(LST.elcpwstn_cls_nm) = '한전거래' THEN '태양광' ELSE MAX(LST.elcpwstn_cls_nm) END AS elcpwstn_cls_nm, LST.elcpwstn_cd, CASE WHEN MAX(LST.elcpwstn_cls_nm) = '한전거래' THEN MAX(LST.elcpwstn_nm) || '(한전거래)' ELSE MAX(LST.elcpwstn_nm) END AS elcpwstn_nm, MAX(hq_cd) AS hq_cd, MAX(LST.cstct_vu) AS cstct_vu, MAX(LST.cstct_nm) AS cstct_nm, MAX(LST.elcpwstn_cpcty) AS elcpwstn_cpcty, ROUND(NVL(SUM(LST.r2val), 0), 2) AS r2, MAX(dsply_ordr) AS dsply_ordr FROM ( SELECT /*+ LEADING(BASE LT2) */ MONTH_LIST.mt, BASE.elcpwstn_nm, BASE.elcpwstn_cd, BASE.centr_elyrs_yn, LT2.elyrs_plan_qy / 1000 / 1000 AS r2val, /* W / 1000 / 1000 => MW */ BASE.hq_cd, BASE.cstct_vu, BASE.cstct_nm, BASE.elcpwstn_cls_cd, BASE.elcpwstn_cls_nm, BASE.elcpwstn_cpcty, BASE.dsply_ordr FROM MONTH_LIST, ( SELECT elcpwstn_cd, elcpwstn_nm, DECODE(centr_elyrs_yn, 'X', 'N', centr_elyrs_yn ) AS centr_elyrs_yn, AS hq_cd, cstct_vu, ( SELECT stext FROM HRM.vm_hr01a01 WHERE SYSDATE BETWEEN strdt AND enddt AND objid IN ( SELECT DISTINCT CASE WHEN MIN(depth) OVER(PARTITION BY kostl) = depth THEN objid ELSE NULL END FROM HRM.vm_hr01a01 WHERE SYSDATE BETWEEN strdt AND enddt AND TRIM(kostl) IS NOT NULL ) AND kostl = LPAD(cstct_vu, 10, '0') ) AS cstct_nm, elcpwstn_cls_cd, ( SELECT DECODE(cmmn_cd, '0004', '태양광', '0005', '태양광', '0007', '보소수력', cmmn_cd_nm ) AS cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'WRO' AND cls_cd = 'WRO_3003' AND cmmn_cd = elcpwstn_cls_cd ) AS elcpwstn_cls_nm, elcpwstn_cpcty, accnut_acnt_cd, dsply_ordr FROM WRO.tc_eg10101 WHERE IN ( SELECT objid FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsBasinDivCd}
) AND centr_elyrs_yn IN ('Y', 'N', 'X') AND accnut_acnt_cd LIKE '' || '%' ) BASE, ( SELECT stdr_de, elcpwstn_cd, ROUND(elyrs_plan_qy, 2) AS elyrs_plan_qy, ROUND(excclc_amt, 2) AS excclc_amt FROM ( SELECT SUBSTR(stdr_de, 0, 6) AS stdr_de, elcpwstn_cd, SUM(elyrs_qy) AS elyrs_plan_qy, SUM(excclc_amt) AS excclc_amt FROM WRO.tm_eg04105 WHERE stdr_de BETWEEN SUBSTR(( SELECT MIN(mt) FROM MONTH_LIST ), 0, 6) || '01' AND SUBSTR(( SELECT MAX(mt) FROM MONTH_LIST ), 0, 6) || '31' AND excclc_div_cd = '0001' /* 자체 */ GROUP BY SUBSTR(stdr_de, 0, 6), elcpwstn_cd UNION ALL SELECT SUBSTR(stdr_plan_ym, 0, 6) AS stdr_plan_ym, elcpwstn_cd, SUM(elyrs_qy) * 1000 AS elyrs_plan_qy, SUM(splval_amt) AS excclc_amt FROM WRO.tm_eg04117 WHERE stdr_plan_ym BETWEEN SUBSTR(( SELECT MIN(mt) FROM MONTH_LIST ), 0, 6) AND SUBSTR(( SELECT MAX(mt) FROM MONTH_LIST ), 0, 6) GROUP BY SUBSTR(stdr_plan_ym, 0, 6), elcpwstn_cd ) ) LT2 WHERE BASE.elcpwstn_cd = LT2.elcpwstn_cd(+) AND MONTH_LIST.mt = LT2.stdr_de(+) ) LST GROUP BY SUBSTR(LST.mt, 0, 4), LST.elcpwstn_cls_cd, LST.elcpwstn_cd ) GROUP BY mt, elcpwstn_cls_cd, hq_cd ORDER BY inqire_de, elcpwstn_cls_nm, hq_cd

/* DSBRD_PC_Dao_retrieveCnstnChartList */ WITH MONTH_LIST AS ( SELECT /*+ MATERIALZE */ TO_CHAR(ADD_MONTHS(TO_DATE(SUBSTR(#{strtDt}, 0, 6), 'yyyyMM'), LEVEL - 1), 'yyyyMM') AS mt FROM DUAL CONNECT BY LEVEL <= MONTHS_BETWEEN(TO_DATE(SUBSTR(#{endDt}, 0, 6), 'yyyyMM'), TO_DATE(SUBSTR(#{strtDt}, 0, 6), 'yyyyMM')) + 1 ), CNSTN_DATA_INIT_LIST AS ( SELECT /*+ MATERIALZE LEADING(BBB AAA) */ AS dscfc_lclhq_cd, ( SELECT cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'SC' AND cls_cd = 'GHG_1001' AND cmmn_cd = ) AS dscfc_lclhq_nm, BBB.dscfc_bplc_cd, ( SELECT cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'SC' AND cls_cd = 'GHG_1002' AND cmmn_cd = BBB.dscfc_bplc_cd ) AS dscfc_bplc_nm, DECODE(BBB.dscfc_procs_ty_cd, '01', '01', '02', '02', '03', '03', '99') AS dscfc_procs_ty_cd, ( SELECT B.cmmn_cd_nm FROM ( SELECT cmmn_cd, cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'SC' AND cls_cd = 'GHG_0024' ) A, ( SELECT usr_dfn_vu2, cmmn_cd_nm FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_1003' ) B WHERE A.cmmn_cd = B.usr_dfn_vu2 AND A.cmmn_cd = DECODE(BBB.dscfc_procs_ty_cd, '01', '01', '02', '02', '03', '03', '99') ) AS dscfc_procs_ty_nm, BBB.dscfc_use_fuel_div_cd, AAA.dscfc_use_de, AAA.sum_dscfc_usgqty FROM GHG.tm_gg01101 BBB, ( SELECT ABC.dscfc_id, ABC.dscfc_use_de, NVL(MAX(ABC.usgqty), 0) AS sum_dscfc_usgqty FROM ( SELECT AA.dscfc_id, AA.dscfc_use_de, CASE WHEN AA.dsqty_cfrml_parm_id IN ('2005', '2001') THEN MAX(AA.dscfc_usgqty) END AS usgqty FROM ( SELECT /*+ LEADING(B A) */ A.dscfc_id, A.dscfc_use_de, B.dsqty_cfrml_parm_id, B.dsqty_cfrml_parm_nm, A.dscfc_usgqty FROM GHG.tm_rq01103 A, GHG.tm_gg01104 B WHERE ( (A.dscfc_use_slip_no IS NOT NULL AND A.dscfc_use_slip_no NOT LIKE 'TMP%') OR A.dscfc_use_slip_prcs_ty_cd = '1' ) AND A.dsqty_cfrml_parm_id IN ('2005', '2001') AND A.dscfc_use_de BETWEEN SUBSTR(( SELECT MIN(mt) FROM MONTH_LIST ), 0, 6) || '01' AND SUBSTR(( SELECT MAX(mt) FROM MONTH_LIST ), 0, 6) || '31' AND A.dsqty_cfrml_parm_id = B.dsqty_cfrml_parm_id ) AA GROUP BY AA.dscfc_id, AA.dscfc_use_de, AA.dsqty_cfrml_parm_id, AA.dsqty_cfrml_parm_nm ) ABC GROUP BY ABC.dscfc_id, ABC.dscfc_use_de ) AAA WHERE BBB.dscfc_id = AAA.dscfc_id(+) AND BBB.dscfc_use_yn = '1' AND BBB.dscfc_regist_stat_div_cd = '1' AND BBB.dscfc_use_fuel_div_cd = '61' /* 전기 */ AND BBB.dscfc_lclhq_cd != '88888888' /* 위탁 */ ), CNSTN_DATA_LIST AS ( SELECT /*+ MATERIALZE */ SUBSTR(dscfc_use_de, 0, 4) AS dscfc_use_de, MAX(dscfc_procs_ty_nm) AS dscfc_procs_ty_nm, MAX(dscfc_lclhq_nm) AS dscfc_lclhq_nm, ROUND(NVL(SUM(sum_dscfc_usgqty / 1000), 0), 2) AS sum_dscfc_usgqty /* kW / 1000 => MW */ FROM CNSTN_DATA_INIT_LIST WHERE IN ( SELECT objid FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsBasinDivCd}
) AND dscfc_use_de IS NOT NULL GROUP BY SUBSTR(dscfc_use_de, 0, 4), dscfc_lclhq_cd, dscfc_procs_ty_cd ORDER BY dscfc_use_de, dscfc_procs_ty_cd, dscfc_lclhq_cd ) SELECT dscfc_use_de AS inqire_de, dscfc_procs_ty_nm AS elcpwstn_cls_nm, dscfc_lclhq_nm AS hq_nm, sum_dscfc_usgqty AS inqire_iem_vu FROM CNSTN_DATA_LIST
